import {{ Injectable }} from '@nestjs/common';
import {{ TaskService }} from './models/task.model';
import {{ TaskServiceRepository }} from './repositories/task.repository';

@Injectable()
export class TaskServiceService {{
  constructor(
    private readonly repository: TaskServiceRepository,
  ) {{}}

  async findAll(): Promise<TaskService[]> {{
    return this.repository.findAll();
  }}

  async findById(id: string): Promise<TaskService | null> {{
    return this.repository.findById(id);
  }}

  async create(data: Partial<TaskService>): Promise<TaskService> {{
    return this.repository.create(data);
  }}

  async update(id: string, data: Partial<TaskService>): Promise<TaskService> {{
    return this.repository.update(id, data);
  }}
}}

